/**
 * 偏好设置模块图片资源类型声明。
 */
/** `.jpg` 资源模块声明。 */
declare module '*.jpg' {
  /** 资源文件地址。 */
  const src: string;
  /** 默认导出资源地址。 */
  export default src;
}

/** `.jpeg` 资源模块声明。 */
declare module '*.jpeg' {
  /** 资源文件地址。 */
  const src: string;
  /** 默认导出资源地址。 */
  export default src;
}

/** `.png` 资源模块声明。 */
declare module '*.png' {
  /** 资源文件地址。 */
  const src: string;
  /** 默认导出资源地址。 */
  export default src;
}

/** `.gif` 资源模块声明。 */
declare module '*.gif' {
  /** 资源文件地址。 */
  const src: string;
  /** 默认导出资源地址。 */
  export default src;
}

/** `.webp` 资源模块声明。 */
declare module '*.webp' {
  /** 资源文件地址。 */
  const src: string;
  /** 默认导出资源地址。 */
  export default src;
}
